import { Badge } from "reactstrap";
import React from "react";
import { ElapsedTimer } from "../../../common/ElapsedTimer";
import { status } from "../../../../helper/appHelper";

export const evaColumns = (isTruck) => {
  let arr = [
    {
      name: "VA Number",
      selector: "ZVA_NUMBER",
      sortable: true,
      minWidth: "180px",
    },
  ];
  if (isTruck === undefined) {
    arr = [
      ...arr,
      {
        name: "Vehicle Number",
        selector: "TRAILER_NO",
        sortable: true,
        minWidth: "150px",
        cell: (row) => {
          return row.TRUCK_NO ? row.TRUCK_NO : row.TRAILER_NO;
        },
      },
      {
        name: "Vehicle Type",
        selector: "TRAILER_NO",
        sortable: true,
        minWidth: "150px",
        cell: (row) => {
          return row.TRUCK_NO ? "Truck" : "Trailer";
        },
      },
    ];
  } else {
    arr = [
      ...arr,
      {
        name: isTruck ? "Truck No" : "Trailer No",
        selector: isTruck ? "TRUCK_NO" : "TRAILER_NO",
        sortable: true,
        minWidth: "150px",
      },
    ];
  }
  return [
    ...arr,
    {
      name: "Driver No",
      selector: "DRIVER_NO",
      sortable: true,
      minWidth: "150px",
    },
    {
      name: "Duration",
      sortable: false,
      minWidth: "150px",
      cell: (row) => {
        return <ElapsedTimer date={row.DateAdded} />;
      },
    },
    {
      name: "Waiting At",
      selector: "VEHICLE_STATUS",
      sortable: true,
      minWidth: "150px",
      cell: (row) => {
        const s = status[row.VEHICLE_STATUS] ? status[row.VEHICLE_STATUS] : {};
        return (
          <Badge color={s.color} pill>
            {s.title}
          </Badge>
        );
      },
    },
    {
      name: "Plant Id",
      selector: "PLANT_ID",
      sortable: true,
      minWidth: "150px",
    },
  ];
};
